1	'use server'
2	import { prisma } from '@/lib/prisma'
3	import { requireAdmin } from '@/lib/auth'
4	import { termSaveSchema } from './schema'
5	import type { ActionResult } from '@/lib/errors'
6	
7	export async function createTerm(input: unknown): Promise<ActionResult<{ id: number }>> {
8	  await requireAdmin()
9	  const parsed = termSaveSchema.safeParse(input)
10	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
11	
12	  const term = await prisma.term.create({ data: parsed.data })
13	  return { success: true, data: { id: term.id } }
14	}
15	
16	export async function updateTerm(id: number, input: unknown): Promise<ActionResult> {
17	  await requireAdmin()
18	  const parsed = termSaveSchema.safeParse(input)
19	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
20	
21	  await prisma.term.update({ where: { id }, data: parsed.data })
22	  return { success: true, data: undefined }
23	}
24	
25	export async function deleteTerm(id: number): Promise<ActionResult> {
26	  await requireAdmin()
27	  await prisma.term.delete({ where: { id } })
28	  return { success: true, data: undefined }
29	}
30	
31	export async function addTermWord(termId: number, wordId: number, seqNo: number): Promise<ActionResult> {
32	  await requireAdmin()
33	  try {
34	    await prisma.termWord.create({ data: { termId, wordId, seqNo } })
35	  } catch {
36	    return { success: false, error: '단어 추가 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
37	  }
38	  return { success: true, data: undefined }
39	}
40	
41	export async function removeTermWord(termId: number, wordId: number): Promise<ActionResult> {
42	  await requireAdmin()
43	  try {
44	    await prisma.termWord.delete({ where: { termId_wordId: { termId, wordId } } })
45	  } catch {
46	    return { success: false, error: '단어 제거 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
47	  }
48	  return { success: true, data: undefined }
49	}
